[[nodiscard]] inline constexpr std::optional<std::string_view> qzss_dcx_ex1_target_area_code_en_lookup(uint16_t id) {
    uint16_t lo = 0, hi = 1980;
    while (lo < hi) {
        uint16_t mid = static_cast<uint16_t>(lo + (hi - lo) / 2);
        if (QZSS_DCX_EX1_TARGET_AREA_CODE_EN_TABLE[mid].id == id) return QZSS_DCX_EX1_TARGET_AREA_CODE_EN_TABLE[mid].label;
        if (QZSS_DCX_EX1_TARGET_AREA_CODE_EN_TABLE[mid].id < id) lo = mid + 1;
        else hi = mid;
    }
    return std::nullopt;
}

